#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_SIZE 500005
int arr[MAX_SIZE];
int compare(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int M;
    scanf("%d", &M);
    int N = 0;
    for (int i = 0; i < M; i++) {
        int type;
        scanf("%d", &type);
        if (type == 0) {
            int x;
            scanf("%d", &x);
            arr[N++] = x;
        } else if (type == 1) {
            int L, R, x;
            scanf("%d %d %d", &L, &R, &x);
            int max = 0;
            for (int j = L - 1; j < R; j++) {
                max = (max > (arr[j] ^ x)) ? max : (arr[j] ^ x);
            }
            printf("%d\n", max);
        } else if (type == 2) {
            int k;
            scanf("%d", &k);
            N -= k;
        } else if (type == 3) {
            int L, R, x;
            scanf("%d %d %d", &L, &R, &x);
            int count = 0;
            for (int j = L - 1; j < R; j++) {
                if (arr[j] <= x) count++;
            }
            printf("%d\n", count);
        } else if (type == 4) {
            int L, R, k;
            scanf("%d %d %d", &L, &R, &k);
            int* temp = (int*)malloc((R - L + 1) * sizeof(int));
            for (int j = L - 1; j < R; j++) {
                temp[j - L + 1] = arr[j];
            }
            qsort(temp, R - L + 1, sizeof(int), compare);
            printf("%d\n", temp[k - 1]);
            free(temp);
        }
    }
    return 0;
}

