import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static final int MAX_SIZE = 500005;
    static int[] arr = new int[MAX_SIZE];
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int M = sc.nextInt();
        int N = 0;
        for (int i = 0; i < M; i++) {
            int type = sc.nextInt();
            if (type == 0) {
                int x = sc.nextInt();
                arr[N++] = x;
            } else if (type == 1) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int x = sc.nextInt();
                int max = 0;
                for (int j = L - 1; j < R; j++) {
                    max = Math.max(max, arr[j] ^ x);
                }
                System.out.println(max);
            } else if (type == 2) {
                int k = sc.nextInt();
                N -= k;
            } else if (type == 3) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int x = sc.nextInt();
                int count = 0;
                for (int j = L - 1; j < R; j++) {
                    if (arr[j] <= x) count++;
                }
                System.out.println(count);
            } else if (type == 4) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int k = sc.nextInt();
                int[] temp = new int[R - L + 1];
                for (int j = L - 1; j < R; j++) {
                    temp[j - L + 1] = arr[j];
                }
                Arrays.sort(temp);
                System.out.println(temp[k - 1]);
            }
        }
    }
}

